// Preparar datos de publicación
const meta = $('📋 Obtener metadata del video').item.json;
const input = $('📥 Entrada desde Producer').item.json;

const hashtags = Array.isArray(meta.hashtags) ? meta.hashtags : JSON.parse(meta.hashtags || '[]');
const hashtagStr = hashtags.map(h => '#' + h).join(' ');

return [{
  json: {
    video_id: input.video_id,
    video_url: input.video_url,
    topic_id: input.topic_id,
    script_id: input.script_id,
    topic: input.topic,
    // YouTube
    yt_title: meta.title || input.topic,
    yt_description: (meta.description || '') + '\n\n' + hashtagStr,
    yt_hashtags: hashtags,
    // TikTok / Instagram / Facebook
    short_caption: (meta.title || input.topic) + '\n\n' + hashtagStr.substring(0, 300),
    thumbnail_text: meta.thumbnail_text || ''
  }
}];

