parameters.jsCode:
const blotato = $input.first().json;
const publish = $('⚙️ Preparar publicación').item.json;

// Extraer IDs por plataforma si Blotato los devuelve
const platforms = ['youtube', 'tiktok', 'instagram', 'facebook'];
const results = [];

for (const platform of platforms) {
  const platformData = blotato.results?.[platform] || blotato.platforms?.[platform] || {};
  results.push({
    json: {
      video_id: publish.video_id,
      platform: platform,
      platform_post_id: platformData.id || platformData.post_id || blotato.id || null,
      platform_url: platformData.url || platformData.share_url || null,
      title_used: platform === 'youtube' ? publish.yt_title : publish.short_caption.split('\n')[0],
      description_used: platform === 'youtube' ? publish.yt_description : publish.short_caption,
      hashtags_used: publish.yt_hashtags
    }
  });
}

return results;
